function sumOfArray<T>(arr: T[]): number {
    let sum: number = 0;
    for (let i: number = 0; i < arr.length; i++) {
        if (typeof arr[i] === 'number' || typeof arr[i] === 'bigint') {
            sum += arr[i];
        }
    }
    return sum;
}

